        }

        let memoKey = (remainingSteps << 24) | (position << 16) | (isTight ? 1 : 0)
        if let cached = memo[memoKey] {
            return cached
        }

        let maxDigit = isTight ? bits[position] : 1
        var total: Int64 = 0

