            let newIsTight = isTight && (digit == maxDigit)
            let newRemainingSteps: Int
            if digit == 1 {
                newRemainingSteps = remainingSteps - 1
            } else {
                newRemainingSteps = remainingSteps
            }
            if newRemainingSteps >= 0 {
                total += countNumbers(newRemainingSteps, position + 1, newIsTight, bits)
            }
        }

        memo[memoKey] = total
        return total
    }

    func getNumbersWithPopcountDepth(_ k: Int) -> Int64 {
        var low: Int64 = 1
        var high: Int64 = n
        var result: Int64 = 0

        while low <= high {
            let mid = (low + high) / 2
            let bits = String(mid, radix: 2).map { Int(String($0))! }
            memo.removeAll()
            let count = countNumbers(k, 0, true, bits)

