        memo.removeAll()
        if result == 0 {
            return 0
        }

        let upperBits = String(result, radix: 2).map { Int(String($0))! }
        let upperCount = countNumbers(k, 0, true, upperBits)

        let lowerBits = String(result - 1, radix: 2).map { Int(String($0))! }
        let lowerCount = countNumbers(k, 0, true, lowerBits)

        return upperCount - lowerCount
    }

    let kInt = Int(k)
    if kInt == 1 {
        let bits = String(n, radix: 2).map { Int(String($0))! }
        memo.removeAll()
        let total = countNumbers(1, 0, true, bits)
        return total
    }

    let depthK = getNumbersWithPopcountDepth(kInt)
    let depthKMinus1 = kInt > 1 ? getNumbersWithPopcountDepth(kInt - 1) : 0

